310:     /// Internal streaming loop - handles token streaming with optional tools.
311:     fn stream_loop(
312:         &mut self,
313:         tools: Option<Arc<ToolRegistry>>,
314:     ) -> Pin<Box<dyn Stream<Item = Result<StreamToken, AgentError>> + Send>> {
315:         let (tx, rx) = tokio::sync::mpsc::channel(32);
316: 
317:         let config = self.config.clone();
318:         let messages = self.message_log.clone();
319:         let llm = self.llm.clone();
320:         let tools_for_request = tools.as_ref().map(|t| t.to_openai_format_shared());
321: 
322:         tokio::spawn(async move {
323:             let mut messages = messages;
324: 
325:             let mut request_messages = Vec::with_capacity(messages.len() + 1);
326:             request_messages.push(OpenAiMessage::System {
327:                 content: config.system_prompt.clone(),
328:             });
329:             messages.extend_api_format(&mut request_messages);
330: 
331:             let request = LlmRequest {
332:                 model: config.model.clone(),
333:                 messages: request_messages,
334:                 tools: tools_for_request.clone(),
335:                 temperature: config.temperature,
336:                 max_tokens: config.max_tokens,
337:             };
338: 
339:             let stream = llm.stream_complete(request);
340: 
341:             // Pin the stream to use it in a loop
342:             let mut stream = Box::pin(stream);
343: 
344:             while let Some(token_result) = stream.next().await {
345:                 match token_result {
346:                     Ok(token) => {
347:                         // Track message accumulation
348:                         match &token {
349:                             StreamToken::Text(s) => {
350:                                 messages.append_assistant_chunk(s);
351:                             }
352:                             StreamToken::ToolCall { name, args } => {
353:                                 if let Some(ref registry) = tools {
354:                                     let result = registry.execute(name, args).await;
355:                                     match result {
356:                                         Ok(res) => {
357:                                             messages.add_tool_result(
358:                                                 name.clone(),
359:                                                 format_tool_result_content(res),
360:                                             );
361:                                         }
362:                                         Err(e) => {
363:                                             let _ = tx.send(Err(AgentError::Tool(e))).await;
364:                                         }
365:                                     }
366:                                 }
367:                             }
368:                             StreamToken::Done => {}
369:                         }
370: 
371:                         if tx.send(Ok(token)).await.is_err() {
372:                             break;
373:                         }
374:                     }
375:                     Err(e) => {
376:                         let _ = tx.send(Err(AgentError::Session(e.to_string()))).await;
377:                         break;
378:                     }
379:                 }
380:             }
381:         });
382: 
383:         Box::pin(tokio_stream::wrappers::ReceiverStream::new(rx))
384:     }
