18: impl SessionManager {
19:     pub fn new(config: SessionConfig) -> Self {
20:         let storage = SessionStorage::new(config.clone());
21:         let cache = Arc::new(RwLock::new(HashMap::new()));
22: 
23:         Self {
24:             storage,
25:             cache,
26:             config,
27:             cleanup_task: None,
28:         }
29:     }
30: 
31:     pub async fn start_cleanup(&mut self, interval: Duration) {
32:         let cache = self.cache.clone();
33:         let base_dir = self.config.base_dir.clone();
34: 
35:         self.cleanup_task = Some(tokio::spawn(async move {
36:             loop {
37:                 tokio::time::sleep(interval).await;
38:                 Self::cleanup_expired(&cache, &base_dir).await;
39:             }
40:         }));
41:     }
42: 
43:     async fn cleanup_expired(
44:         cache: &Arc<RwLock<HashMap<String, AgentState>>>,
45:         base_dir: &Path,
46:     ) {
47:         let mut cache_guard = cache.write().await;
48:         let mut to_remove = Vec::new();
49: 
50:         for (agent_id, state) in cache_guard.iter() {
51:             if SessionSerializer::is_expired(state) {
52:                 to_remove.push(agent_id.clone());
53:             }
54:         }
55: 
56:         for agent_id in to_remove {
57:             cache_guard.remove(&agent_id);
58:             let _ = tokio::fs::remove_file(base_dir.join(format!("{}.json", agent_id))).await;
59:         }
60:     }
