62:     pub async fn create(&self, agent_id: String) -> Result<AgentState, SessionError> {
63:         if self.exists(&agent_id).await {
64:             return Err(SessionError::AlreadyExists(agent_id));
65:         }
66: 
67:         let state = SessionSerializer::new_state(agent_id.clone());
68: 
69:         {
70:             let mut cache = self.cache.write().await;
71:             cache.insert(agent_id.clone(), state.clone());
72:         }
73: 
74:         self.storage.save(&state).await?;
75: 
76:         Ok(state)
77:     }
78: 
79:     pub async fn get(&self, agent_id: &str) -> Result<AgentState, SessionError> {
80:         {
81:             let cache = self.cache.read().await;
82:             if let Some(state) = cache.get(agent_id) {
83:                 return Ok(state.clone());
84:             }
85:         }
86: 
87:         let state = self.storage.load(agent_id).await?;
88: 
