58:                 }
59:             }
60:         });
61: 
62:         if !self.config.connect.is_empty() {
63:             zenoh_config_json["connect"]["endpoints"] = serde_json::json!(self.config.connect);
64:         }
65: 
66:         if !self.config.listen.is_empty() {
