70:         let zenoh_config: zenoh::Config = serde_json::from_value(zenoh_config_json)
71:             .map_err(|e| ZenohError::Session(e.to_string()))?;
72: 
73:         let session = zenoh::open(zenoh_config).await?;
74:         let session = Arc::new(session);
75:         *guard = Some(session.clone());
