71:         if let Some(error) = resp.error {
72:             return Err(McpError::InitFailed(error.message));
73:         }
74: 
75:         let capabilities = resp
76:             .result
77:             .as_ref()
78:             .and_then(|v| v.get("capabilities"))
79:             .cloned()
80:             .unwrap_or(serde_json::json!({"tools": false, "resources": false, "prompts": false}));
81: 
82:         let caps: ServerCapabilities = serde_json::from_value(capabilities)
83:             .map_err(|e| McpError::Protocol(e.to_string()))?;
84: 
85:         *self.capabilities.lock().unwrap() = Some(caps.clone());
86: 
87:         self.notify("notifications/initialized", None).await?;
88: 
