221:         let req = JsonRpcRequest::new(method, params, id);
222:         let json = serde_json::to_vec(&req)?;
223:         let mut transport = self.transport.lock().await;
224:         transport.send(&json).await?;
225:         
226:         let mut buffer = {
227:             let lock = self.recv_buffer.lock().unwrap();
228:             lock.clone()
229:         };
230:         transport.recv_line(&mut buffer).await?;
231:         let resp: JsonRpcResponse = serde_json::from_str(&buffer)?;
232:         Ok(resp)
233:     }
