143:     fn parse_token(line: &str) -> Option<StreamToken> {
144:         let data: BorrowedOpenAiStreamResponse<'_> = serde_json::from_str(line).ok()?;
145:         for choice in data.choices {
146:             if let Some(content) = choice.delta.content {
147:                 if !content.is_empty() {
148:                     return Some(StreamToken::Text(content.into_owned()));
149:                 }
150:             }
151:             if let Some(calls) = choice.delta.tool_calls {
152:                 for call in calls {
153:                     if let (Some(name), Some(args)) = (call.function.name, call.function.arguments) {
154:                         let args_val: serde_json::Value = serde_json::from_str(args.as_ref()).ok()?;
155:                         return Some(StreamToken::ToolCall {
156:                             name: name.into_owned(),
157:                             args: args_val,
158:                         });
159:                     }
160:                 }
161:             }
162:         }
163:         None
164:     }
