172: impl LlmClient for OpenAiClient {
173:     async fn complete(&self, req: LlmRequest) -> Result<LlmResponse, LlmError> {
174:         let openai_req = self.build_request(req, false);
175:         let response = self
176:             .client
177:             .post(&self.chat_completions_url)
