221:         let url = self.chat_completions_url.clone();
222:         let api_key = self.api_key.clone();
223:         let client = self.client.clone();
224:         let openai_req = serde_json::to_string(&self.build_request(req, true)).ok();
225: 
226:         let (tx, rx) = mpsc::channel(32);
227: 
228:         tokio::spawn(async move {
229:             let body = match openai_req {
230:                 Some(b) => b,
231:                 None => {
232:                     let _ = tx.send(Err(LlmError::Parse("Failed to serialize request".to_string()))).await;
233:                     return;
234:                 }
235:             };
236: 
237:             let response = match client
238:                 .post(&url)
239:                 .header("Authorization", format!("Bearer {}", api_key))
240:                 .header("Content-Type", "application/json")
241:                 .body(body)
242:                 .send()
243:                 .await
244:             {
245:                 Ok(r) => r,
246:                 Err(e) => {
247:                     let _ = tx.send(Err(LlmError::Http(e.to_string()))).await;
248:                     return;
249:                 }
250:             };
251: 
252:             if !response.status().is_success() {
253:                 let status = response.status();
254:                 let body = response.text().await.unwrap_or_default();
255:                 let _ = tx.send(Err(LlmError::Http(format!("HTTP {}: {}", status, body)))).await;
256:                 return;
257:             }
258: 
259:             let body_bytes = match response.bytes().await {
260:                 Ok(b) => b,
261:                 Err(e) => {
262:                     let _ = tx.send(Err(LlmError::Http(e.to_string()))).await;
263:                     return;
264:                 }
265:             };
266: 
267:             let mut decoder = SseDecoder::new();
268: 
269:             for event in decoder.decode_chunk(body_bytes.as_ref()) {
270:                 let token = match event {
271:                     SseEvent::Data(line) => {
272:                         Self::parse_token(&line).map(Ok)
273:                     }
274:                     SseEvent::Done => Some(Ok(StreamToken::Done)),
275:                     SseEvent::Error(msg) => Some(Err(LlmError::Parse(msg))),
276:                 };
277: 
278:                 if let Some(t) = token {
279:                     if tx.send(t).await.is_err() {
280:                         break;
281:                     }
282:                 }
283:             }
284:         });
285: 
286:         Box::pin(ReceiverStream::new(rx))
287:     }
