18:     ///
19:     /// The function will receive arguments as JSON and must return a JSON-serializable result
20:     pub fn new<F>(name: &str, description: &str, schema: serde_json::Value, func: F) -> Self
21:     where
22:         F: Fn(&serde_json::Value) -> Result<serde_json::Value, ToolError> + Send + Sync + 'static,
23:     {
24:         Self {
25:             name: name.to_string(),
26:             description: ToolDescription {
27:                 short: description.to_string(),
28:                 parameters: "JSON object with function parameters".to_string(),
29:             },
30:             schema,
31:             func: Arc::new(func),
32:         }
33:     }
34: 
35:     /// Create a FunctionTool with automatic schema generation for simple numeric functions.
36:     ///
37:     /// This helper creates a schema for functions expecting up to 5 numeric parameters (a, b, c, d, e).
38:     pub fn numeric<F>(name: &str, description: &str, num_params: usize, func: F) -> Self
39:     where
40:         F: Fn(&serde_json::Value) -> Result<serde_json::Value, ToolError> + Send + Sync + 'static,
41:     {
42:         let params = ['a', 'b', 'c', 'd', 'e'];
43:         let mut properties = serde_json::Map::new();
44:         let mut required = Vec::new();
45: 
46:         for i in 0..num_params {
47:             let param_name = params[i];
48:             properties.insert(
49:                 param_name.to_string(),
50:                 serde_json::json!({
51:                     "type": "number",
52:                     "description": format!("Parameter {}", param_name)
53:                 }),
54:             );
55:             required.push(param_name.to_string());
56:         }
57: 
58:         let schema = serde_json::json!({
59:             "type": "object",
60:             "properties": properties,
61:             "required": required
62:         });
63: 
64:         Self::new(name, description, schema, func)
65:     }
66: }
