55:     /// Register a tool with a namespace prefix to avoid conflicts.
56:     /// Tool name will be `{namespace}/{tool_name}`.
57:     pub fn register_with_namespace(
58:         &mut self,
59:         tool: Arc<dyn Tool>,
60:         namespace: &str,
61:     ) -> Result<(), ToolError> {
62:         let tool_name = tool.name().to_string();
63:         let namespaced_name = format!("{}/{}", namespace, tool_name);
64:         
65:         if self.tools.contains_key(&namespaced_name) {
66:             return Err(ToolError::ExecutionFailed(format!(
67:                 "duplicate tool in namespace '{}': {}",
68:                 namespace,
69:                 tool_name
70:             )));
71:         }
72: 
73:         // Create a wrapper tool with the namespaced name
74:         let wrapped = Arc::new(NamespacedTool::new(tool, namespaced_name.clone()));
75:         let weak_wrapped = Arc::downgrade(&wrapped);
76:         self.tool_name_index
77:             .entry(tool_name.clone())
78:             .or_default()
79:             .push(weak_wrapped.clone());
80:         self.namespaced_tool_index
81:             .entry(namespace.to_string())
82:             .or_default()
83:             .insert(tool_name.clone(), weak_wrapped);
84: 
85:         let namespace_entry = self.namespace_index.entry(namespace.to_string()).or_default();
86:         if namespace_entry.is_empty() {
87:             self.namespaces.push(namespace.to_string());
88:         }
89:         namespace_entry.push(namespaced_name.clone());
90:         
91:         let schema = wrapped.cached_schema();
92:         self.schema_cache.insert(namespaced_name.clone(), schema);
93:         self.push_openai_format_entry(wrapped.as_ref());
94:         
95:         self.tools.insert(namespaced_name, wrapped);
96:         Ok(())
97:     }
