112:     /// Get a tool by name (with or without namespace).
113:     /// If no namespace is provided, searches all namespaces using index (O(1)).
114:     pub fn get(&self, name: &str) -> Option<Arc<dyn Tool>> {
115:         // First try exact match (could be namespaced or not)
116:         if let Some(tool) = self.tools.get(name).cloned() {
117:             return Some(tool);
118:         }
119: 
120:         // Fast O(1) lookup using index instead of O(n) scan
121:         if let Some(weak_tools) = self.tool_name_index.get(name) {
122:             for weak_tool in weak_tools {
123:                 if let Some(tool) = weak_tool.upgrade() {
124:                     return Some(tool);
125:                 }
126:             }
127:         }
128: 
129:         None
130:     }
